"""Realtime import + silver build, verified against real captured O1/O2 records."""
import gzip
import json
import sys
from pathlib import Path

import duckdb

ROOT = Path(__file__).resolve().parents[1]
sys.path.insert(0, str(ROOT / "tools" / "jravan"))
from import_realtime import run_import  # noqa: E402

from keibamon_core.ingestion.jravan_silver import build_jravan_odds_timeseries  # noqa: E402
from keibamon_core.paths import LakePaths  # noqa: E402

# Real JV-Link realtime 0B30 records (Takarazuka R11, 13:39 JST snapshot).
O1_RAW = "O112026061420260614090304110614133918007773010075050200600303205317040566100500240106032207072240180804670909041408101762151107561212117314130698111411521315017306160056021700650418196316                                                                                010018002502020022003105030252038816040070010510050013001601060052007908070263040517080053008009090050007607100171026315110084012712120108016513130072010811140112017014150034005006160018002603170020002904180273042118                                                                                                                        "
O2_RAW = ""


def _wrap(rid, raw, ch):
    ts = "2026-06-14T04:40:07.587695Z"
    return {"source_name": "jravan_rt", "source_record_id": f"{rid}:{ch}",
            "raw_uri": "2026061409030411", "content_hash": ch, "ingested_at": ts,
            "published_time": ts, "available_at": ts, "record_id": rid,
            "spec": f"RT_{rid}", "raw": raw, "race_key": "2026061409030411",
            "captured_at": ts, "seconds_to_post": -7193, "pool": "0B30",
            "record_type": rid}


def _make_usb(root: Path):
    d = root / "incoming" / "realtime" / "20260614" / "2026061409030411"
    d.mkdir(parents=True)
    with gzip.open(d / "20260614T044007Z.ndjson.gz", "wt", encoding="utf-8") as fh:
        fh.write(json.dumps(_wrap("O1", O1_RAW, "hashO1")) + "\n")
        fh.write(json.dumps(_wrap("O2", O2_RAW, "hashO2")) + "\n")


def test_realtime_import_is_idempotent_and_lands_bronze(tmp_path):
    usb, lake_root = tmp_path / "xfer", tmp_path / "lake"
    _make_usb(usb)
    out = run_import(usb, lake_root)
    assert out["written"] == 2 and out["dates"] == ["20260614"]
    o1 = lake_root / "raw" / "jravan_rt" / "rt-20260614" / "O1.rt-20260614.ndjson.gz"
    assert o1.exists()
    # re-run: nothing new, nothing duplicated
    out2 = run_import(usb, lake_root)
    assert out2["written"] == 0 and out2["skipped"] == 2
    with gzip.open(o1, "rt", encoding="utf-8") as fh:
        assert sum(1 for line in fh if line.strip()) == 1  # still one O1 record


def test_realtime_feeds_odds_timeseries_with_correct_odds(tmp_path):
    usb, lake_root = tmp_path / "xfer", tmp_path / "lake"
    _make_usb(usb)
    run_import(usb, lake_root)
    lake = LakePaths(root=lake_root)
    res = build_jravan_odds_timeseries(lake)
    assert res["jravan_odds_timeseries"] > 0
    ds = (lake.silver_dataset("jravan_odds_timeseries") / "**" / "*.parquet").as_posix()
    # Croix du Nord (#05) win odds 2.4, sourced from the realtime capture, PIT-stamped
    row = duckdb.sql(
        f"SELECT race_id, win_odds, source_name, available_at "
        f"FROM read_parquet('{ds}', hive_partitioning=true) "
        f"WHERE source_name='jravan_rt' AND pool='win' AND sel='05'"
    ).fetchone()
    assert row is not None
    assert row[0] == "jra-20260614-09-11"
    assert abs(row[1] - 2.4) < 1e-9
    assert str(row[3]).startswith("2026-06-14 04:40:07")  # wrapper PIT time, not announce minute
